#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char A[1001], B[1001];
        scanf("%s", A);
        scanf("%s", B);
        long long count = 0;
        for (int LA = 0; LA < N; LA++) {
            for (int RA = LA; RA < N; RA++) {
                for (int LB = 0; LB < N; LB++) {
                    for (int RB = LB; RB < N; RB++) {
                        if (RA - LA == RB - LB) {
                            int hammingDistance = 0;
                            for (int i = 0; i <= RA - LA; i++) {
                                if (A[LA + i] != B[LB + i]) {
                                    hammingDistance++;
                                }
                            }
                            if (hammingDistance <= K) {
                                count++;
                            }
                        }
                    }
                }
            }
        }
        printf("%lld\n", count);
    }
    return 0;
}

