import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            String A = sc.next();
            String B = sc.next();
            long count = 0;
            for (int LA = 0; LA < N; LA++) {
                for (int RA = LA; RA < N; RA++) {
                    for (int LB = 0; LB < N; LB++) {
                        for (int RB = LB; RB < N; RB++) {
                            if (RA - LA == RB - LB) {
                                int hammingDistance = 0;
                                for (int i = 0; i <= RA - LA; i++) {
                                    if (A.charAt(LA + i) != B.charAt(LB + i)) {
                                        hammingDistance++;
                                    }
                                }
                                if (hammingDistance <= K) {
                                    count++;
                                }
                            }
                        }
                    }
                }
            }
            System.out.println(count);
        }
    }
}

